// AUTO-GENERATED: premium Grimoire pages 8–88.
// Lives with the functions (NOT in the public web root) so it is only
// served by auth-check.js after a successful subscriber/admin check.
module.exports = "<!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 THE GRIMOIRE OF REMEMBERED LIGHT \u2014 MASTER EDITION \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n\n      <div class=\"gr-book\">\n        <div class=\"gr-book-title\" style=\"font-size:2.1rem\">The Grimoire of Remembered Light</div>\n        <div class=\"gr-book-sub\">Master Edition \u00b7 A Living Book of Light Magic, Herbal Wisdom, Sacred Ritual, Seasonal Remembrance &amp; Ancestral Knowing</div>\n        <hr class=\"gr-book-rule\">\n        <div class=\"gr-book-sub\">Written for Awaken Again &amp; Amber&rsquo;s Alchemy Apothecary</div>\n      </div>\n\n      <p class=\"gr-text\" style=\"text-align:center;font-style:italic\">This grimoire is a work of light. It is rooted in remembrance, herbal traditions, seasonal folk practices, ancestral reverence, symbolic ritual, self-reflection, and earth-based spirituality.</p>\n      <p class=\"gr-spell\">No curses. No hexes. No domination. No intentional spiritual harm.<br>Only restoration. Only remembrance. Only light.</p>\n\n      <!-- OPENING BLESSING -->\n      <h3 class=\"gr-chapter\">Opening Blessing</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text gr-lead\">To the daughters who remember, to the sons who listen gently, to the healers who still hear the earth, to the seekers who knew there had to be more, to the ones who feel something awaken when rain touches dry soil, when candles flicker, when herbs steep, when moonlight spills through windows, when old stories return &mdash; this book was written for you.</p>\n      <p class=\"gr-text\">The world taught humanity to forget. Forget the seasons. Forget the moon. Forget the medicines growing beneath our feet. Forget the sacred rhythm of rest. Forget ancestral wisdom. Forget intuition. Forget ceremony. Forget stillness. Forget that the body listens. Forget that the earth remembers.</p>\n      <p class=\"gr-text\">This grimoire exists so that remembrance may begin again.</p>\n\n      <!-- TABLE OF CONTENTS -->\n      <h3 class=\"gr-chapter\">Table of Sacred Contents</h3>\n      <hr class=\"gr-chapter-rule\">\n      <div class=\"gr-toc\">\n        <div class=\"gr-toc-book\">Book I \u2014 The Seers and the Sacred Line</div>\n        <div class=\"gr-toc-item\">1. The Origin of the Grimoire</div>\n        <div class=\"gr-toc-item\">2. The Youngest Daughter Tradition</div>\n        <div class=\"gr-toc-item\">3. The Law of Light Magic</div>\n        <div class=\"gr-toc-item\">4. Spiritual Responsibility</div>\n        <div class=\"gr-toc-item\">5. The Ethics of Ritual</div>\n        <div class=\"gr-toc-item\">6. Protection Without Harm</div>\n        <div class=\"gr-toc-item\">7. Why Humanity Forgot</div>\n        <div class=\"gr-toc-item\">8. Returning to Sacred Time</div>\n        <div class=\"gr-toc-book\">Book II \u2014 The Wheel of the Year</div>\n        <div class=\"gr-toc-item\">9. Winter Solstice</div>\n        <div class=\"gr-toc-item\">10. Imbolc &nbsp;\u00b7&nbsp; 11. Spring Equinox</div>\n        <div class=\"gr-toc-item\">12. Beltane &nbsp;\u00b7&nbsp; 13. Summer Solstice</div>\n        <div class=\"gr-toc-item\">14. Lughnasadh &nbsp;\u00b7&nbsp; 15. Autumn Equinox</div>\n        <div class=\"gr-toc-item\">16. Samhain &nbsp;\u00b7&nbsp; 17. Cross-Quarter Days</div>\n        <div class=\"gr-toc-item\">18. Moon Calendars &nbsp;\u00b7&nbsp; 19. Sacred Fire Dates</div>\n        <div class=\"gr-toc-item\">20. Harvest Traditions</div>\n        <div class=\"gr-toc-book\">Book III \u2014 Herbal Wisdom</div>\n        <div class=\"gr-toc-item\">21\u201350. The Spirit of Herbs &amp; the Thirty Sacred Plants</div>\n        <div class=\"gr-toc-item\">Rosemary \u00b7 Lavender \u00b7 Mugwort \u00b7 Chamomile \u00b7 Hibiscus \u00b7 Nettle \u00b7 Sage \u00b7 Thyme \u00b7 Basil \u00b7 Rose \u00b7 and more</div>\n        <div class=\"gr-toc-book\">Book IV \u2014 Rituals of Light</div>\n        <div class=\"gr-toc-item\">51\u201370. Candle Magic \u00b7 Salt Blessings \u00b7 Moon Water \u00b7 Cleansing Baths \u00b7 Kitchen Magic \u00b7 Dreamwork \u00b7 and more</div>\n        <div class=\"gr-toc-book\">Book V \u2014 The Living Pages</div>\n        <div class=\"gr-toc-item\">71\u201380. Subscriber Rituals \u00b7 Seasonal Recipes \u00b7 Botanical Beauty \u00b7 Soap Blessings \u00b7 Future Seer Pages</div>\n      </div>\n\n      <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BOOK I \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n      <div class=\"gr-book\">\n        <div class=\"gr-book-num\">Book One</div>\n        <div class=\"gr-book-title\">The Seers and the Sacred Line</div>\n        <hr class=\"gr-book-rule\">\n      </div>\n\n      <h3 class=\"gr-chapter\">Chapter 1 \u2014 The Origin of the Grimoire</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text gr-lead\">The first keeper of this grimoire lived beside the edge of a dark forest where winters were long and silence taught survival.</p>\n      <p class=\"gr-text\">She was not called a witch. That word had not yet become feared. She was called a keeper. A listener. A wise daughter. A woman who knew the language of herbs, weather, dreams, smoke, grief, and birth.</p>\n      <p class=\"gr-text\">She learned when roots should be gathered. She learned how long lavender must dry before sleep magic became strongest. She learned how rosemary held memory. She learned that the moon altered not only oceans, but people.</p>\n      <p class=\"gr-text\">She wrote everything down. Not because she believed herself powerful &mdash; because she feared humanity would forget. And eventually, they did.</p>\n      <p class=\"gr-text\">So the book continued. One generation after another. Passed only to the youngest daughter born into the next line &mdash; believed to carry the freshest bridge between what had been and what had not yet arrived.</p>\n      <p class=\"gr-text\">Each seer added pages. One added herbal remedies. One added moon calendars. One added grief rituals. One added kitchen blessings. One added candle rites. One added dream symbols. One added warnings. One added hope. And now the book opens again.</p>\n\n      <h3 class=\"gr-chapter\">Chapter 2 \u2014 The Law of Light Magic</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">The first law of this grimoire is simple:</p>\n      <p class=\"gr-spell\">Never intentionally use spiritual practice to harm another living being.</p>\n      <p class=\"gr-text\">No curse written in rage can remain free of the rage that created it. Light magic asks something harder. It asks: Can you heal instead of punish? Can you release instead of control? Can you protect without destroying? Can you become whole instead of becoming feared?</p>\n      <p class=\"gr-label\">The magic within these pages uses</p>\n      <ul class=\"gr-list\">\n        <li>herbs \u00b7 breath \u00b7 intention \u00b7 prayer \u00b7 gratitude</li>\n        <li>moonlight \u00b7 firelight \u00b7 water \u00b7 salt \u00b7 ritual timing</li>\n        <li>journaling \u00b7 offerings \u00b7 ancestral remembrance \u00b7 symbolic acts</li>\n      </ul>\n      <p class=\"gr-text\">Magic is not about domination. Magic is relationship &mdash; with the self, with the earth, with consequence, with time, with spirit.</p>\n\n      <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BOOK II \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n      <div class=\"gr-book\">\n        <div class=\"gr-book-num\">Book Two</div>\n        <div class=\"gr-book-title\">The Wheel of the Year</div>\n        <hr class=\"gr-book-rule\">\n      </div>\n\n      <h3 class=\"gr-chapter\">Winter Solstice \u2014 The Return of Light</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text gr-lead\">The Winter Solstice marks the longest night of the year. Ancient people feared the darkness because survival depended upon the return of light.</p>\n      <p class=\"gr-text\">Candles were lit. Evergreen branches were brought indoors. Fires were kept burning. Stories were shared. Warm drinks were brewed from herbs and spices. Many modern traditions still carry these symbols: evergreen trees, candles in windows, wreaths, gift giving, communal feasts, and firelight. Even after the original meanings became hidden, the symbols remained.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Winter Solstice Ritual \u2726</p>\n        <p class=\"gr-label\">What You Need</p>\n        <ul class=\"gr-list\"><li>white candle</li><li>rosemary</li><li>cinnamon</li><li>warm tea</li><li>journal</li></ul>\n        <p class=\"gr-label\">Instructions</p>\n        <ol class=\"gr-steps\">\n          <li>Light the candle after sunset.</li>\n          <li>Hold rosemary in your hands.</li>\n          <li>Speak the blessing below.</li>\n          <li>Drink tea slowly.</li>\n          <li>Write what darkness you are ready to leave behind.</li>\n          <li>Burn the paper safely.</li>\n          <li>Thank the returning light.</li>\n        </ol>\n        <p class=\"gr-spell\">The light returns. So too shall hope. So too shall healing. So too shall I.</p>\n      </div>\n\n      <h3 class=\"gr-chapter\">Beltane \u2014 Fire and Life</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">Beltane celebrated fertility, creativity, passion, beauty, and the life force of the earth. Bonfires were lit. Flowers crowned the hair. Communities danced. Fields were blessed. Animals were guided between fires for symbolic protection.</p>\n      <p class=\"gr-text\">Modern society remembers fragments: flowers in spring, maypoles, ribbons, celebrations of love and beauty. But Beltane originally reminded humanity that life itself is sacred.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Beltane Beauty Blessing \u2726</p>\n        <p class=\"gr-label\">Ingredients</p>\n        <ul class=\"gr-list\"><li>rose petals</li><li>lavender</li><li>hibiscus</li><li>honey</li><li>spring water</li></ul>\n        <p class=\"gr-text\">Steep flowers into warm water. Add honey. Wash hands and face while speaking:</p>\n        <p class=\"gr-spell\">May I bloom without apology. May I soften without weakness. May I love without fear. May I carry beauty that begins within.</p>\n      </div>\n\n      <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BOOK III \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n      <div class=\"gr-book\">\n        <div class=\"gr-book-num\">Book Three</div>\n        <div class=\"gr-book-title\">Herbal Wisdom</div>\n        <hr class=\"gr-book-rule\">\n      </div>\n\n      <h3 class=\"gr-chapter\">Rosemary \u2014 Herb of Remembrance</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text gr-lead\">Rosemary has long been associated with memory, loyalty, protection, and mental clarity. In ancient traditions, rosemary was burned in homes for purification and placed near doors for energetic protection.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Rosemary Steam Ritual \u2726</p>\n        <p class=\"gr-label\">What You Need</p>\n        <ul class=\"gr-list\"><li>rosemary</li><li>hot water</li><li>towel</li></ul>\n        <p class=\"gr-text\">Place rosemary into steaming water. Cover head gently with towel. Breathe deeply. Imagine mental fog dissolving.</p>\n        <p class=\"gr-spell\">What is meant for me remains. What clouds my sight releases. My mind remembers clarity.</p>\n      </div>\n\n      <h3 class=\"gr-chapter\">Lavender \u2014 Herb of Peace</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">Lavender has been used for centuries in sleep rituals, cleansing baths, dream pillows, and emotional calming.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Sleep Sachet Ritual \u2726</p>\n        <p class=\"gr-label\">Combine</p>\n        <ul class=\"gr-list\"><li>lavender</li><li>chamomile</li><li>mugwort</li><li>rose petals</li></ul>\n        <p class=\"gr-text\">Place beneath pillow. Before sleep say:</p>\n        <p class=\"gr-spell\">May my dreams teach gently. May my body soften. May my spirit rest.</p>\n      </div>\n\n      <h3 class=\"gr-chapter\">Mugwort \u2014 Dream Herb</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">Mugwort has traditionally been connected with dreaming, intuition, and symbolic inner journeys. This herb should be approached respectfully and in moderation.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Dream Tea Ritual \u2726</p>\n        <p class=\"gr-label\">Ingredients</p>\n        <ul class=\"gr-list\"><li>mugwort</li><li>chamomile</li><li>lavender</li></ul>\n        <p class=\"gr-text\">Drink lightly before sleep. Keep journal nearby. Upon waking, write every fragment remembered. Dream memory strengthens when honored.</p>\n      </div>\n\n      <h3 class=\"gr-chapter\">Hibiscus \u2014 Vitality and Sacred Beauty</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">Hibiscus carries the symbolism of vitality, passion, confidence, and heart-centered living.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Hibiscus Moon Tea \u2726</p>\n        <p class=\"gr-label\">Ingredients</p>\n        <ul class=\"gr-list\"><li>hibiscus</li><li>cinnamon</li><li>ginger</li><li>honey</li></ul>\n        <p class=\"gr-text\">This tea may be shared beneath the full moon while reflecting on gratitude and emotional renewal.</p>\n      </div>\n\n      <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BOOK IV \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n      <div class=\"gr-book\">\n        <div class=\"gr-book-num\">Book Four</div>\n        <div class=\"gr-book-title\">Rituals of Light</div>\n        <hr class=\"gr-book-rule\">\n      </div>\n\n      <h3 class=\"gr-chapter\">The Sacred Bath of Release</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text gr-lead\">Water has always carried symbolic meaning. Humans instinctively use water during grief, cleansing, prayer, rebirth, and transition.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Ritual Bath \u2726</p>\n        <p class=\"gr-label\">Ingredients</p>\n        <ul class=\"gr-list\"><li>sea salt</li><li>rosemary</li><li>lavender</li><li>chamomile</li><li>rose petals</li></ul>\n        <p class=\"gr-label\">Optional</p>\n        <ul class=\"gr-list\"><li>candlelight</li><li>soft music</li><li>moonlight</li></ul>\n        <p class=\"gr-label\">Instructions</p>\n        <ol class=\"gr-steps\"><li>Fill bath.</li><li>Add herbs.</li><li>Sit quietly.</li><li>Place hands over heart.</li><li>Speak the blessing below.</li></ol>\n        <p class=\"gr-spell\">I release what no longer belongs within me. I call my energy home. I soften. I heal. I remember who I am.</p>\n      </div>\n\n      <h3 class=\"gr-chapter\">Home Blessing Ritual</h3>\n      <hr class=\"gr-chapter-rule\">\n      <div class=\"gr-ritual\">\n        <p class=\"gr-label\">Ingredients</p>\n        <ul class=\"gr-list\"><li>rosemary</li><li>salt</li><li>candle</li><li>bowl of water</li></ul>\n        <p class=\"gr-label\">Instructions</p>\n        <ol class=\"gr-steps\"><li>Open windows.</li><li>Move clockwise through home.</li><li>Sprinkle salt lightly near doors.</li><li>Carry candle carefully.</li><li>Speak blessings instead of demands.</li></ol>\n        <p class=\"gr-spell\">May this home hold peace. May this home hold safety. May this home hold nourishment. May all who enter bring goodwill.</p>\n      </div>\n\n      <!-- \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BOOK V \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 -->\n      <div class=\"gr-book\">\n        <div class=\"gr-book-num\">Book Five</div>\n        <div class=\"gr-book-title\">The Living Pages</div>\n        <div class=\"gr-book-sub\">Sacred Recipes, Beauty Rituals &amp; Dreamwork</div>\n        <hr class=\"gr-book-rule\">\n      </div>\n\n      <h3 class=\"gr-chapter\">Moon Milk for Deep Sleep</h3>\n      <hr class=\"gr-chapter-rule\">\n      <div class=\"gr-ritual\">\n        <p class=\"gr-label\">Ingredients</p>\n        <ul class=\"gr-list\"><li>warm oat milk</li><li>chamomile</li><li>lavender</li><li>cinnamon</li><li>honey</li><li>nutmeg</li></ul>\n        <p class=\"gr-label\">Instructions</p>\n        <ol class=\"gr-steps\"><li>Warm milk gently.</li><li>Steep herbs.</li><li>Add honey.</li><li>Drink slowly before bed.</li></ol>\n        <p class=\"gr-text\" style=\"margin-bottom:0\">Pair with <em>DreamEase</em> rituals for evening grounding.</p>\n      </div>\n\n      <h3 class=\"gr-chapter\">Hearth Bread of Gratitude</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">Traditional breads were once baked intentionally during harvest periods to symbolize abundance and communal survival.</p>\n      <p class=\"gr-spell\">As grain becomes nourishment, may my life become nourishment. May I share what I have. May I never forget gratitude.</p>\n\n      <h3 class=\"gr-chapter\">Sacred Oils and Balms</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">The body deserves reverence. Self-care can become ritual when approached with intention.</p>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Beauty Balm Blessing \u2726</p>\n        <p class=\"gr-text\">When applying balm:</p>\n        <p class=\"gr-spell\">May my body know gentleness. May my reflection become kinder. May I age with wisdom. May beauty become something I feel.</p>\n      </div>\n      <div class=\"gr-ritual\">\n        <p class=\"gr-ritual-name\">\u2726 Hair Regrowth Ritual \u2726</p>\n        <p class=\"gr-text\">Inspired by traditional botanical oil infusions and modern herbal self-care practices.</p>\n        <p class=\"gr-label\">Suggested Herbs</p>\n        <ul class=\"gr-list\"><li>rosemary</li><li>nettle</li><li>hibiscus</li><li>ginger</li><li>cayenne</li><li>fenugreek</li><li>thyme</li><li>safflower</li></ul>\n        <p class=\"gr-text\" style=\"margin-bottom:0\">Massage slowly into scalp while visualizing restoration and vitality.</p>\n      </div>\n\n      <h3 class=\"gr-chapter\">Dreamwork and Symbols</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">Dream memory fades quickly. The subconscious responds when its messages are honored. Keep a journal beside the bed. Write immediately upon waking. Do not judge symbolism too quickly.</p>\n      <p class=\"gr-label\">Common Symbols</p>\n      <ul class=\"gr-list\">\n        <li><strong style=\"color:var(--parchment)\">Water</strong> \u2014 emotional movement</li>\n        <li><strong style=\"color:var(--parchment)\">Fire</strong> \u2014 transformation</li>\n        <li><strong style=\"color:var(--parchment)\">Birds</strong> \u2014 perspective or messages</li>\n        <li><strong style=\"color:var(--parchment)\">Teeth</strong> \u2014 fear or transition</li>\n        <li><strong style=\"color:var(--parchment)\">Doors</strong> \u2014 opportunities or thresholds</li>\n        <li><strong style=\"color:var(--parchment)\">Forests</strong> \u2014 the unknown self</li>\n        <li><strong style=\"color:var(--parchment)\">Moon</strong> \u2014 intuition</li>\n      </ul>\n\n      <h3 class=\"gr-chapter\">The Future Pages</h3>\n      <hr class=\"gr-chapter-rule\">\n      <p class=\"gr-text\">This grimoire was never meant to end. Every generation adds wisdom. Every season adds experience. Every healing becomes another page.</p>\n      <p class=\"gr-label\">Subscribers may receive</p>\n      <ul class=\"gr-list\">\n        <li>new seasonal rituals \u00b7 monthly recipes \u00b7 moon calendars</li>\n        <li>herbal teachings \u00b7 printable pages \u00b7 sacred journal prompts</li>\n        <li>guided reflections \u00b7 candle rituals \u00b7 solstice ceremonies</li>\n        <li>ancestral remembrance practices</li>\n      </ul>\n      <p class=\"gr-text\">The grimoire lives because remembrance lives.</p>\n\n      <!-- FINAL BLESSING -->\n      <div class=\"gr-book\"><hr class=\"gr-book-rule\"><div class=\"gr-book-title\" style=\"font-size:1.4rem\">Final Blessing</div></div>\n      <p class=\"gr-blessing\">May this book never become a tool of fear. May it remain rooted in healing. May it reconnect people to the earth. May it soften the overwhelmed. May it strengthen the grieving. May it remind humanity that wisdom once lived in kitchens, gardens, firesides, forests, and grandmothers.</p>\n      <p class=\"gr-blessing\" style=\"color:var(--gold-light)\">And may every person who opens these pages remember:<br>The light was never truly lost. Only forgotten.<br>Until now.</p>";
